"use client";

import { useEffect, useMemo, useState } from "react";
import Navbar from "../../components/Navbar";
import BackgroundParticles from "../../components/BackgroundParticles";
import AvatarImage from "../../components/AvatarImage";
import { useSleeper } from "../../context/SleeperContext";

const seasonNow = new Date().getFullYear();
const num = (value) => Number(value || 0);
const getJson = async (url) => { const response=await fetch(url,{cache:"no-store"}); if(!response.ok)throw new Error(); return response.json(); };
async function concurrentMap(rows,limit,worker){const results=new Array(rows.length);let cursor=0;await Promise.all(Array.from({length:Math.min(limit,rows.length)},async()=>{while(cursor<rows.length){const index=cursor++;results[index]=await worker(rows[index],index);}}));return results;}
const nameFor = (user, roster) => user?.metadata?.team_name || user?.display_name || user?.username || `Roster ${roster?.roster_id || "—"}`;
function Panel({children,className=""}){return <div className={`rounded-[28px] border border-white/10 bg-gradient-to-b from-slate-900/90 to-slate-950/85 ${className}`}>{children}</div>;}
function Stat({label,value,detail}){return <div className="rounded-2xl border border-white/10 bg-white/[0.035] p-3"><div className="text-[9px] font-semibold uppercase tracking-[.17em] text-white/35">{label}</div><div className="mt-1 text-xl font-black">{value}</div>{detail?<div className="mt-1 text-[10px] text-white/35">{detail}</div>:null}</div>;}

function ManagerCompare({ owners, league, players }) {
  const [leftId, setLeftId] = useState("");
  const [rightId, setRightId] = useState("");
  useEffect(() => {
    const ids = owners.map(({ roster }) => String(roster.roster_id));
    setLeftId((current) => ids.includes(current) ? current : ids[0] || "");
    setRightId((current) => ids.includes(current) && current !== (ids[0] || "") ? current : ids[1] || ids[0] || "");
  }, [owners]);
  const summarize = (entry) => {
    if (!entry) return null;
    const ids = (entry.roster.players || []).map(String);
    const ages = ids.map((id) => num(players?.[id]?.age)).filter(Boolean);
    const positions = ids.reduce((map, id) => { const pos=String(players?.[id]?.position||"Other").toUpperCase(); map[pos]=(map[pos]||0)+1; return map; }, {});
    const points = num(entry.roster.settings?.fpts) + num(entry.roster.settings?.fpts_decimal) / 100;
    const potential = num(entry.roster.settings?.ppts) + num(entry.roster.settings?.ppts_decimal) / 100;
    return { ...entry, ids, positions, points, potential, efficiency: potential ? Math.round(points / potential * 100) : null, averageAge: ages.length ? ages.reduce((a,b)=>a+b,0)/ages.length : null };
  };
  const left = summarize(owners.find(({ roster }) => String(roster.roster_id) === leftId));
  const right = summarize(owners.find(({ roster }) => String(roster.roster_id) === rightId));
  if (!left || !right) return null;
  const shared = left.ids.filter((id) => right.ids.includes(id));
  const unique = (side, other) => side.ids.filter((id) => !other.ids.includes(id)).slice(0,8);
  const metrics = [
    ["Record", `${num(left.roster.settings?.wins)}-${num(left.roster.settings?.losses)}`, `${num(right.roster.settings?.wins)}-${num(right.roster.settings?.losses)}`],
    ["Fantasy points", left.points.toFixed(1), right.points.toFixed(1)],
    ["Lineup capture", left.efficiency == null ? "—" : `${left.efficiency}%`, right.efficiency == null ? "—" : `${right.efficiency}%`],
    ["Roster players", left.ids.length, right.ids.length],
    ["Average age", left.averageAge?.toFixed(1) || "—", right.averageAge?.toFixed(1) || "—"],
  ];
  const selectClass = "w-full rounded-xl border border-white/10 bg-slate-950 px-3 py-2.5 text-sm";
  return <Panel className="mt-5 overflow-hidden"><div className="border-b border-white/10 bg-[radial-gradient(circle_at_80%_0%,rgba(34,211,238,.12),transparent_40%)] p-5"><div className="text-[10px] font-semibold uppercase tracking-[.2em] text-cyan-200/55">Head-to-head workspace</div><h2 className="mt-1 text-2xl font-black">Manager Compare</h2><p className="mt-1 text-xs text-white/38">Compare two managers inside {league?.name || "the selected league"}. Public results describe roster outcomes, not manager quality.</p></div><div className="grid gap-3 p-4 sm:grid-cols-[1fr_auto_1fr] sm:items-end"><label className="text-[10px] font-semibold uppercase tracking-wider text-white/35">Manager one<select value={leftId} onChange={(event)=>setLeftId(event.target.value)} className={`mt-2 ${selectClass}`}>{owners.map(({roster,user})=><option key={roster.roster_id} value={roster.roster_id}>{nameFor(user,roster)}</option>)}</select></label><div className="hidden pb-3 text-xs font-black text-white/20 sm:block">VS</div><label className="text-[10px] font-semibold uppercase tracking-wider text-white/35">Manager two<select value={rightId} onChange={(event)=>setRightId(event.target.value)} className={`mt-2 ${selectClass}`}>{owners.map(({roster,user})=><option key={roster.roster_id} value={roster.roster_id}>{nameFor(user,roster)}</option>)}</select></label></div><div className="border-t border-white/[0.06] p-4"><div className="grid grid-cols-[1fr_auto_1fr] gap-3 text-center"><div className="truncate text-lg font-black text-cyan-100">{nameFor(left.user,left.roster)}</div><div className="text-[9px] uppercase tracking-widest text-white/20">Metric</div><div className="truncate text-lg font-black text-violet-100">{nameFor(right.user,right.roster)}</div>{metrics.map(([label,a,b])=><div key={label} className="contents"><div className="rounded-xl bg-cyan-300/[0.045] p-2.5 font-bold">{a}</div><div className="self-center text-[9px] uppercase tracking-wider text-white/30">{label}</div><div className="rounded-xl bg-violet-300/[0.045] p-2.5 font-bold">{b}</div></div>)}</div><div className="mt-4 grid gap-3 lg:grid-cols-3"><div className="rounded-2xl bg-white/[0.025] p-4"><div className="text-[10px] font-semibold uppercase text-cyan-100/50">Position build · manager one</div><div className="mt-2 flex flex-wrap gap-2">{Object.entries(left.positions).sort((a,b)=>b[1]-a[1]).map(([pos,count])=><span key={pos} className="rounded-lg bg-white/[0.05] px-2 py-1 text-xs"><b>{pos}</b> {count}</span>)}</div></div><div className="rounded-2xl bg-white/[0.025] p-4"><div className="text-[10px] font-semibold uppercase text-white/35">Shared players · {shared.length}</div><div className="mt-2 text-xs leading-5 text-white/50">{shared.length ? shared.slice(0,10).map((id)=>players?.[id]?.full_name||id).join(" · ") : "No roster overlap."}</div></div><div className="rounded-2xl bg-white/[0.025] p-4"><div className="text-[10px] font-semibold uppercase text-violet-100/50">Position build · manager two</div><div className="mt-2 flex flex-wrap gap-2">{Object.entries(right.positions).sort((a,b)=>b[1]-a[1]).map(([pos,count])=><span key={pos} className="rounded-lg bg-white/[0.05] px-2 py-1 text-xs"><b>{pos}</b> {count}</span>)}</div></div></div><details className="mt-3 rounded-2xl border border-white/[0.06] bg-white/[0.02] p-3"><summary className="cursor-pointer text-xs font-semibold text-white/55">Show distinguishing players</summary><div className="mt-3 grid gap-3 sm:grid-cols-2"><div><b className="text-xs text-cyan-100/65">Only on {nameFor(left.user,left.roster)}</b><p className="mt-1 text-xs leading-5 text-white/38">{unique(left,right).map((id)=>players?.[id]?.full_name||id).join(" · ")||"None"}</p></div><div><b className="text-xs text-violet-100/65">Only on {nameFor(right.user,right.roster)}</b><p className="mt-1 text-xs leading-5 text-white/38">{unique(right,left).map((id)=>players?.[id]?.full_name||id).join(" · ")||"None"}</p></div></div></details></div></Panel>;
}

function OpenManagerCompare({ season, players, initialLeft = "" }) {
  const [names,setNames]=useState([initialLeft,""]);
  const [results,setResults]=useState([null,null]);
  const [errors,setErrors]=useState(["",""]);
  const [loading,setLoading]=useState(false);
  useEffect(()=>{if(initialLeft)setNames(current=>[current[0]||initialLeft,current[1]]);},[initialLeft]);
  const load=async(username)=>{
    const clean=String(username||"").trim();
    const response=await fetch(`https://api.sleeper.app/v1/user/${encodeURIComponent(clean)}`,{cache:"no-store"});
    if(!response.ok)throw new Error(`No Sleeper manager was found for “${clean}”.`);
    const user=await response.json();
    if(!user?.user_id)throw new Error(`No Sleeper manager was found for “${clean}”.`);
    const leagues=await getJson(`https://api.sleeper.app/v1/user/${user.user_id}/leagues/nfl/${season}`).catch(()=>[]);
    const rows=await concurrentMap(leagues,10,async league=>{
      const [rosters,users]=await Promise.all([
        getJson(`https://api.sleeper.app/v1/league/${league.league_id}/rosters`).catch(()=>[]),
        getJson(`https://api.sleeper.app/v1/league/${league.league_id}/users`).catch(()=>[]),
      ]);
      return{league,users,roster:rosters.find(roster=>String(roster.owner_id)===String(user.user_id))};
    });
    const owned=rows.filter(row=>row.roster);
    const ids=owned.flatMap(row=>row.roster.players||[]).map(String);
    const wins=owned.reduce((sum,row)=>sum+num(row.roster.settings?.wins),0);
    const losses=owned.reduce((sum,row)=>sum+num(row.roster.settings?.losses),0);
    const points=owned.reduce((sum,row)=>sum+num(row.roster.settings?.fpts)+num(row.roster.settings?.fpts_decimal)/100,0);
    const ages=ids.map(id=>num(players?.[id]?.age)).filter(Boolean);
    const positions=ids.reduce((map,id)=>{const pos=String(players?.[id]?.position||"Other").toUpperCase();map[pos]=(map[pos]||0)+1;return map;},{});
    const network=new Map();
    rows.forEach(row=>(row.users||[]).forEach(member=>{if(String(member.user_id)===String(user.user_id))return;const entry=network.get(String(member.user_id))||{user:member,leagues:[]};entry.leagues.push(row.league);network.set(String(member.user_id),entry);}));
    const games=wins+losses;
    return{user,leagues,ids,wins,losses,points,positions,network,unique:new Set(ids).size,winPct:games?wins/games:null,averageAge:ages.length?ages.reduce((a,b)=>a+b,0)/ages.length:null,dynasty:leagues.filter(league=>num(league?.settings?.type)===2).length,bestBall:leagues.filter(league=>num(league?.settings?.best_ball)===1).length};
  };
  const submit=async(event)=>{
    event.preventDefault();
    const nextErrors=names.map((name,index)=>name.trim()?"":`Enter manager ${index===0?"one":"two"}'s Sleeper username.`);
    if(nextErrors.some(Boolean)){setErrors(nextErrors);return;}
    setLoading(true);setErrors(["",""]);
    const settled=await Promise.allSettled(names.map(load));
    const next=[...results];const failures=["",""];
    settled.forEach((result,index)=>{if(result.status==="fulfilled")next[index]=result.value;else failures[index]=result.reason?.message||"This manager could not be loaded.";});
    setResults(next);setErrors(failures);setLoading(false);
  };
  const [left,right]=results;
  const sharedLeagues=left&&right?left.leagues.filter(league=>right.leagues.some(other=>String(other.league_id)===String(league.league_id))):[];
  const sharedPlayers=left&&right?[...new Set(left.ids)].filter(id=>right.ids.includes(id)):[];
  const sharedPeople=left&&right?[...left.network.entries()].filter(([id])=>right.network.has(id)).map(([id,row])=>({id,user:row.user,left:row.leagues,right:right.network.get(id).leagues})).sort((a,b)=>(b.left.length+b.right.length)-(a.left.length+a.right.length)):[];
  const managerCard=(data,tone)=>{const cyan=tone==="cyan";return <div className={`rounded-3xl border p-4 ${cyan?"border-cyan-300/15 bg-cyan-300/[0.045]":"border-violet-300/15 bg-violet-300/[0.045]"}`}><div className="flex items-center gap-3">{data.user.avatar?<img src={`https://sleepercdn.com/avatars/thumbs/${data.user.avatar}`} alt="" className="h-12 w-12 rounded-2xl"/>:<div className="grid h-12 w-12 place-items-center rounded-2xl bg-white/[0.06] text-lg font-black">{String(data.user.display_name||data.user.username||"?")[0]}</div>}<div className="min-w-0"><div className={`truncate text-lg font-black ${cyan?"text-cyan-100":"text-violet-100"}`}>{data.user.display_name||data.user.username}</div><div className="truncate text-xs text-white/35">@{data.user.username}</div></div></div><div className="mt-4 grid grid-cols-2 gap-2 sm:grid-cols-4"><Stat label="Leagues" value={data.leagues.length}/><Stat label="Record" value={`${data.wins}-${data.losses}`}/><Stat label="Win rate" value={data.winPct==null?"—":`${Math.round(data.winPct*100)}%`}/><Stat label="Points" value={Math.round(data.points).toLocaleString()}/></div></div>;};
  const detail=(title,summary,children,open=false)=><details open={open} className="group rounded-2xl border border-white/[0.08] bg-white/[0.022]"><summary className="flex cursor-pointer list-none items-center gap-3 p-4"><div className="min-w-0 flex-1"><div className="font-bold">{title}</div><div className="mt-1 text-xs text-white/35">{summary}</div></div><span className="text-white/30 transition group-open:rotate-180">⌄</span></summary><div className="border-t border-white/[0.06] p-4">{children}</div></details>;
  return <Panel className="mt-5 overflow-hidden"><div className="border-b border-white/10 bg-[radial-gradient(circle_at_90%_0%,rgba(139,92,246,.14),transparent_40%)] p-5 sm:p-6"><div className="text-[10px] font-semibold uppercase tracking-[.2em] text-violet-200/55">Manager comparison studio</div><h2 className="mt-1 text-2xl font-black sm:text-3xl">Compare any two Sleeper managers</h2><p className="mt-2 max-w-3xl text-xs leading-5 text-white/42">Portfolio performance, roster construction, shared leagues, and network overlap—without requiring the managers to share a league.</p></div><form onSubmit={submit} className="grid gap-3 p-4 sm:p-5 lg:grid-cols-[1fr_1fr_auto] lg:items-start">{[0,1].map(index=><label key={index} className="text-xs font-semibold text-white/45">Manager {index===0?"one":"two"}<input value={names[index]} onChange={event=>setNames(current=>current.map((value,i)=>i===index?event.target.value:value))} placeholder="Sleeper username" className="mt-1.5 w-full rounded-xl border border-white/10 bg-slate-950 px-4 py-3 text-sm font-normal text-white outline-none focus:border-violet-300/35"/>{errors[index]?<span className="mt-1.5 block text-xs font-normal text-rose-200">{errors[index]}</span>:null}</label>)}<button disabled={loading} className="rounded-xl bg-violet-300/12 px-6 py-3 text-sm font-bold text-violet-100 disabled:opacity-50 lg:mt-5">{loading?"Building comparison…":"Compare managers"}</button></form>{left&&right&&!errors.some(Boolean)?<div className="space-y-4 border-t border-white/[0.06] p-4 sm:p-5"><div className="grid gap-3 xl:grid-cols-2">{managerCard(left,"cyan")}{managerCard(right,"violet")}</div><div className="grid grid-cols-2 gap-3 sm:grid-cols-4"><Stat label="Shared leagues" value={sharedLeagues.length} detail="Exact league IDs"/><Stat label="Shared people" value={sharedPeople.length} detail="League-mate overlap"/><Stat label="Shared players" value={sharedPlayers.length} detail="Portfolio exposure"/><Stat label="Combined network" value={new Set([...left.network.keys(),...right.network.keys()]).size} detail="Unique managers"/></div><div className="grid gap-3 xl:grid-cols-2">{detail("Portfolio construction",`${left.dynasty} vs ${right.dynasty} dynasty leagues`,<div className="space-y-4"><div className="grid grid-cols-2 gap-3"><div className="rounded-xl bg-cyan-300/[0.04] p-3 text-xs"><b className="text-cyan-100">{left.user.display_name||left.user.username}</b><div className="mt-2 text-white/45">{left.dynasty} dynasty · {left.bestBall} Best Ball<br/>{left.unique} unique players · age {left.averageAge?.toFixed(1)||"—"}</div></div><div className="rounded-xl bg-violet-300/[0.04] p-3 text-xs"><b className="text-violet-100">{right.user.display_name||right.user.username}</b><div className="mt-2 text-white/45">{right.dynasty} dynasty · {right.bestBall} Best Ball<br/>{right.unique} unique players · age {right.averageAge?.toFixed(1)||"—"}</div></div></div><div className="grid gap-3 sm:grid-cols-2">{[left,right].map(data=><div key={data.user.user_id} className="flex flex-wrap gap-2">{Object.entries(data.positions).sort((a,b)=>b[1]-a[1]).map(([pos,count])=><span key={pos} className="rounded-lg bg-white/[0.05] px-2.5 py-1.5 text-xs"><b>{pos}</b> {count}</span>)}</div>)}</div></div>,true)}{detail("Shared leagues",sharedLeagues.length?`${sharedLeagues.length} exact matches`:"No shared leagues",sharedLeagues.length?<ul className="space-y-2">{sharedLeagues.map(league=><li key={league.league_id} className="flex items-center justify-between gap-3 rounded-xl bg-white/[0.035] px-3 py-2.5 text-xs"><span className="truncate font-semibold">{league.name}</span><span className="shrink-0 text-white/30">{league.total_rosters||"—"} teams</span></li>)}</ul>:<div className="text-sm text-white/38">These managers do not share an exact league in {season}.</div>)}{detail("Shared manager network",sharedPeople.length?`${sharedPeople.length} mutual league-mates`:"No mutual league-mates",sharedPeople.length?<ul className="grid gap-2 sm:grid-cols-2">{sharedPeople.map(row=><li key={row.id} className="rounded-xl bg-white/[0.035] p-3"><div className="truncate text-sm font-semibold">{row.user.display_name||row.user.username}</div><div className="mt-1 text-[10px] text-white/30">@{row.user.username||"unknown"} · {row.left.length} / {row.right.length} league connections</div></li>)}</ul>:<div className="text-sm text-white/38">No overlapping league-mates were found in their {season} portfolios.</div>)}{detail("Shared player exposure",sharedPlayers.length?`${sharedPlayers.length} players rostered by both`:"No shared players",sharedPlayers.length?<div className="grid gap-2 sm:grid-cols-2">{sharedPlayers.map(id=><div key={id} className="flex items-center gap-3 rounded-xl bg-white/[0.035] p-2.5"><AvatarImage name={players?.[id]?.full_name} playerId={id} size={34} className="rounded-xl" alt=""/><div className="min-w-0"><div className="truncate text-sm font-semibold">{players?.[id]?.full_name||id}</div><div className="text-[10px] text-white/30">{players?.[id]?.position||"—"} · {players?.[id]?.team||"FA"}</div></div></div>)}</div>:<div className="text-sm text-white/38">Their current player portfolios do not overlap.</div>)}</div></div>:null}</Panel>;
}

function OpenManagerCompareLegacy({ season, players, initialLeft = "" }) {
  const [leftName,setLeftName]=useState(initialLeft);
  const [rightName,setRightName]=useState("");
  const [left,setLeft]=useState(null);
  const [right,setRight]=useState(null);
  const [errors,setErrors]=useState({});
  const [loading,setLoading]=useState(false);
  useEffect(()=>{if(initialLeft&&!leftName)setLeftName(initialLeft);},[initialLeft,leftName]);
  const loadSummary=async(username)=>{
    const clean=String(username||"").trim();
    const userResponse=await fetch(`https://api.sleeper.app/v1/user/${encodeURIComponent(clean)}`,{cache:"no-store"});
    if(!userResponse.ok)throw new Error(`No Sleeper manager was found for “${clean}”.`);
    const user=await userResponse.json();
    if(!user?.user_id)throw new Error(`No Sleeper manager was found for “${clean}”.`);
    const leagues=await getJson(`https://api.sleeper.app/v1/user/${user.user_id}/leagues/nfl/${season}`).catch(()=>[]);
    const rows=await concurrentMap(leagues,10,async league=>{
      const [rosters,users]=await Promise.all([
        getJson(`https://api.sleeper.app/v1/league/${league.league_id}/rosters`).catch(()=>[]),
        getJson(`https://api.sleeper.app/v1/league/${league.league_id}/users`).catch(()=>[]),
      ]);
      return{league,users,roster:rosters.find(row=>String(row.owner_id)===String(user.user_id))};
    });
    const owned=rows.filter(row=>row.roster);
    const ids=owned.flatMap(row=>row.roster.players||[]).map(String);
    const wins=owned.reduce((sum,row)=>sum+num(row.roster.settings?.wins),0);
    const losses=owned.reduce((sum,row)=>sum+num(row.roster.settings?.losses),0);
    const points=owned.reduce((sum,row)=>sum+num(row.roster.settings?.fpts)+num(row.roster.settings?.fpts_decimal)/100,0);
    const ages=ids.map(id=>num(players?.[id]?.age)).filter(Boolean);
    const positions=ids.reduce((map,id)=>{const pos=String(players?.[id]?.position||"Other").toUpperCase();map[pos]=(map[pos]||0)+1;return map;},{});
    const network=new Map();
    rows.forEach(row=>(row.users||[]).forEach(member=>{if(String(member.user_id)===String(user.user_id))return;const current=network.get(String(member.user_id))||{user:member,leagues:[]};current.leagues.push(row.league);network.set(String(member.user_id),current);}));
    const dynasty=leagues.filter(league=>num(league?.settings?.type)===2).length;
    const bestBall=leagues.filter(league=>num(league?.settings?.best_ball)===1).length;
    const games=wins+losses;
    return{user,leagues,rows,network,ids,wins,losses,points,positions,dynasty,bestBall,winPct:games?wins/games:null,unique:new Set(ids).size,averageAge:ages.length?ages.reduce((a,b)=>a+b,0)/ages.length:null};
  };
  const compare=async(event)=>{
    event?.preventDefault();setErrors({});
    const next={};
    if(!leftName.trim())next.left="Enter the first Sleeper username.";
    if(!rightName.trim())next.right="Enter the second Sleeper username.";
    if(Object.keys(next).length){setErrors(next);return;}
    setLoading(true);
    const [a,b]=await Promise.allSettled([loadSummary(leftName),loadSummary(rightName)]);
    if(a.status==="fulfilled")setLeft(a.value);else next.left=a.reason?.message||"First manager could not be loaded.";
    if(b.status==="fulfilled")setRight(b.value);else next.right=b.reason?.message||"Second manager could not be loaded.";
    setErrors(next);setLoading(false);
  };
  const shared=left&&right?left.ids.filter((id,index)=>left.ids.indexOf(id)===index&&right.ids.includes(id)):[];
  const sharedLeagues=left&&right?left.leagues.filter(league=>right.leagues.some(other=>String(other.league_id)===String(league.league_id))):[];
  const sharedNetwork=left&&right?[...left.network.entries()].filter(([id])=>right.network.has(id)).map(([id,row])=>({id,user:row.user,leftLeagues:row.leagues,rightLeagues:right.network.get(id).leagues})).sort((a,b)=>(b.leftLeagues.length+b.rightLeagues.length)-(a.leftLeagues.length+a.rightLeagues.length)):[];
  const metrics=left&&right?[
    ["League count",left.leagues.length,right.leagues.length],
    ["Shared leagues",sharedLeagues.length?`${sharedLeagues.length} · ${sharedLeagues.map(league=>league.name).join(", ")}`:"None",sharedLeagues.length?`${sharedLeagues.length} · ${sharedLeagues.map(league=>league.name).join(", ")}`:"None"],
    ["Network reach",left.network.size,right.network.size],
    ["Shared league-mates",sharedNetwork.length?`${sharedNetwork.length} · ${sharedNetwork.slice(0,8).map(row=>row.user.display_name||row.user.username).join(", ")}`:"None",sharedNetwork.length?`${sharedNetwork.length} · ${sharedNetwork.slice(0,8).map(row=>row.user.display_name||row.user.username).join(", ")}`:"None"],
    ["Dynasty leagues",left.dynasty,right.dynasty],
    ["Best Ball leagues",left.bestBall,right.bestBall],
    ["Combined record",`${left.wins}-${left.losses}`,`${right.wins}-${right.losses}`],
    ["Portfolio win rate",left.winPct==null?"—":`${Math.round(left.winPct*100)}%`,right.winPct==null?"—":`${Math.round(right.winPct*100)}%`],
    ["Fantasy points",Math.round(left.points).toLocaleString(),Math.round(right.points).toLocaleString()],
    ["Unique players",left.unique,right.unique],
    ["Average age",left.averageAge?.toFixed(1)||"—",right.averageAge?.toFixed(1)||"—"],
  ]:[];
  return <Panel className="mt-5 overflow-hidden"><div className="border-b border-white/10 p-5"><div className="text-[10px] font-semibold uppercase tracking-[.2em] text-violet-200/55">Open comparison</div><h2 className="mt-1 text-2xl font-black">Compare any two Sleeper managers</h2><p className="mt-1 text-xs text-white/38">No shared league is required. Results summarize each manager’s complete {season} public portfolio.</p></div><form onSubmit={compare} className="grid gap-3 p-4 sm:grid-cols-[1fr_1fr_auto] sm:items-start"><label className="text-xs text-white/45">Manager one<input value={leftName} onChange={event=>setLeftName(event.target.value)} placeholder="Sleeper username" className="mt-1.5 w-full rounded-xl border border-white/10 bg-slate-950 px-3 py-3 text-sm text-white"/></label><label className="text-xs text-white/45">Manager two<input value={rightName} onChange={event=>setRightName(event.target.value)} placeholder="Sleeper username" className="mt-1.5 w-full rounded-xl border border-white/10 bg-slate-950 px-3 py-3 text-sm text-white"/></label><button className="mt-5 rounded-xl bg-violet-300/12 px-5 py-3 text-sm font-bold text-violet-100">{loading?"Comparing…":"Compare"}</button>{errors.left?<div className="text-xs text-rose-200 sm:col-start-1">{errors.left}</div>:null}{errors.right?<div className="text-xs text-rose-200 sm:col-start-2">{errors.right}</div>:null}</form>{left&&right&&!Object.keys(errors).length?<div className="border-t border-white/[0.06] p-4"><div className="grid grid-cols-[1fr_auto_1fr] gap-3 text-center"><div className="truncate text-lg font-black text-cyan-100">{left.user.display_name||left.user.username}</div><div className="text-[9px] uppercase tracking-widest text-white/20">Metric</div><div className="truncate text-lg font-black text-violet-100">{right.user.display_name||right.user.username}</div>{metrics.map(([label,a,b])=><div key={label} className="contents"><div className="rounded-xl bg-cyan-300/[0.045] p-2.5 font-bold">{a}</div><div className="self-center text-[9px] uppercase tracking-wider text-white/30">{label}</div><div className="rounded-xl bg-violet-300/[0.045] p-2.5 font-bold">{b}</div></div>)}</div><div className="mt-4 grid gap-3 lg:grid-cols-3"><div className="rounded-2xl bg-white/[0.025] p-4"><div className="text-[10px] uppercase text-cyan-100/45">Manager one build</div><div className="mt-2 flex flex-wrap gap-2">{Object.entries(left.positions).sort((a,b)=>b[1]-a[1]).map(([pos,count])=><span key={pos} className="rounded-lg bg-white/[0.05] px-2 py-1 text-xs"><b>{pos}</b> {count}</span>)}</div></div><div className="rounded-2xl bg-white/[0.025] p-4"><div className="text-[10px] uppercase text-white/35">Shared player exposure · {shared.length}</div><div className="mt-2 text-xs leading-5 text-white/50">{shared.length?shared.slice(0,12).map(id=>players?.[id]?.full_name||id).join(" · "):"No shared current-season players."}</div></div><div className="rounded-2xl bg-white/[0.025] p-4"><div className="text-[10px] uppercase text-violet-100/45">Manager two build</div><div className="mt-2 flex flex-wrap gap-2">{Object.entries(right.positions).sort((a,b)=>b[1]-a[1]).map(([pos,count])=><span key={pos} className="rounded-lg bg-white/[0.05] px-2 py-1 text-xs"><b>{pos}</b> {count}</span>)}</div></div></div></div>:null}</Panel>;
}

function WeeklyPortfolioReport({ user, leagues, season, players }) {
  const [week,setWeek]=useState(1);
  const [report,setReport]=useState(null);
  const [loading,setLoading]=useState(false);
  const [error,setError]=useState("");
  const build=async()=>{
    if(!user?.user_id)return;
    setLoading(true);setError("");
    try{
      const rows=await concurrentMap(leagues||[],8,async league=>{
        const [rosters,matchups,transactions]=await Promise.all([
          getJson(`https://api.sleeper.app/v1/league/${league.league_id}/rosters`).catch(()=>[]),
          getJson(`https://api.sleeper.app/v1/league/${league.league_id}/matchups/${week}`).catch(()=>[]),
          getJson(`https://api.sleeper.app/v1/league/${league.league_id}/transactions/${week}`).catch(()=>[]),
        ]);
        const roster=rosters.find(row=>String(row.owner_id)===String(user.user_id));
        const mine=matchups.find(row=>String(row.roster_id)===String(roster?.roster_id));
        const opponent=matchups.find(row=>String(row.matchup_id)===String(mine?.matchup_id)&&String(row.roster_id)!==String(mine?.roster_id));
        const involved=transactions.filter(tx=>new Set([...(tx.roster_ids||[]),...Object.values(tx.adds||{}),...Object.values(tx.drops||{})].map(String)).has(String(roster?.roster_id)));
        return{league,roster,mine,opponent,transactions:involved};
      });
      const played=rows.filter(row=>row.mine&&row.opponent);
      const wins=played.filter(row=>num(row.mine.points)>num(row.opponent.points)).length;
      const losses=played.filter(row=>num(row.mine.points)<num(row.opponent.points)).length;
      const ties=played.length-wins-losses;
      const total=played.reduce((sum,row)=>sum+num(row.mine.points),0);
      const margins=played.map(row=>({...row,margin:num(row.mine.points)-num(row.opponent.points)}));
      const pointTotals=new Map();
      played.forEach(row=>Object.entries(row.mine.players_points||{}).forEach(([id,points])=>pointTotals.set(String(id),(pointTotals.get(String(id))||0)+num(points))));
      const performers=[...pointTotals.entries()].map(([id,points])=>({id,points,name:players?.[id]?.full_name||id})).sort((a,b)=>b.points-a.points);
      const benchLost=played.reduce((sum,row)=>{const starterSet=new Set((row.mine.starters||[]).map(String));const starterPoints=Object.entries(row.mine.players_points||{}).filter(([id])=>starterSet.has(String(id))).reduce((s,[,p])=>s+num(p),0);const best=(row.mine.players||[]).map(id=>num(row.mine.players_points?.[id])).sort((a,b)=>b-a).slice(0,starterSet.size).reduce((s,p)=>s+p,0);return sum+Math.max(0,best-starterPoints);},0);
      const empty=played.reduce((sum,row)=>sum+(row.mine.starters||[]).filter(id=>!id||String(id)==="0").length,0);
      const activity=rows.flatMap(row=>row.transactions.map(tx=>({tx,league:row.league})));
      setReport({rows,played,wins,losses,ties,total,margins,performers,benchLost,empty,activity});
    }catch{setError("This weekly portfolio report could not be built from Sleeper right now.");}
    finally{setLoading(false);}
  };
  const best=report?.margins?.slice().sort((a,b)=>b.margin-a.margin)[0];
  const worst=report?.margins?.slice().sort((a,b)=>a.margin-b.margin)[0];
  const close=report?.margins?.filter(row=>Math.abs(row.margin)<=5)||[];
  const trades=report?.activity?.filter(row=>row.tx.type==="trade").length||0;
  const waivers=report?.activity?.filter(row=>row.tx.type==="waiver").length||0;
  const adds=report?.activity?.filter(row=>row.tx.type==="free_agent").length||0;
  return <div className="mt-5 space-y-4"><Panel className="overflow-hidden"><div className="border-b border-white/10 bg-[radial-gradient(circle_at_90%_0%,rgba(34,211,238,.14),transparent_40%)] p-5"><div className="text-[10px] font-semibold uppercase tracking-[.2em] text-cyan-200/55">Weekly portfolio report</div><h2 className="mt-1 text-2xl font-black">Every league. One weekly story.</h2><p className="mt-1 text-xs text-white/38">Completed and active matchup data for @{user?.username} across {leagues?.length||0} leagues.</p></div><div className="flex flex-col gap-3 p-4 sm:flex-row sm:items-end"><label className="text-xs text-white/45">NFL week<select value={week} onChange={event=>setWeek(num(event.target.value))} className="mt-1.5 block w-full rounded-xl border border-white/10 bg-slate-950 px-4 py-3 text-sm text-white sm:w-44">{Array.from({length:18},(_,index)=>index+1).map(value=><option key={value} value={value}>Week {value}</option>)}</select></label><button onClick={build} disabled={loading} className="rounded-xl bg-cyan-300/10 px-5 py-3 text-sm font-bold text-cyan-100 disabled:opacity-50">{loading?"Building report…":`Build Week ${week} report`}</button></div></Panel>{error?<div className="rounded-2xl border border-rose-300/15 bg-rose-300/[0.06] p-4 text-sm text-rose-100">{error}</div>:null}{report?<><section className="grid grid-cols-2 gap-3 sm:grid-cols-4 xl:grid-cols-8"><Stat label="Record" value={`${report.wins}-${report.losses}${report.ties?`-${report.ties}`:""}`}/><Stat label="Total points" value={report.total.toFixed(1)}/><Stat label="Avg. score" value={report.played.length?(report.total/report.played.length).toFixed(1):"—"}/><Stat label="Close games" value={close.length} detail="Within five points"/><Stat label="Bench gap" value={report.benchLost.toFixed(1)} detail="Directional estimate"/><Stat label="Empty slots" value={report.empty}/><Stat label="Transactions" value={report.activity.length}/><Stat label="Leagues found" value={report.played.length}/></section><div className="grid gap-4 xl:grid-cols-2"><Panel className="overflow-hidden"><div className="border-b border-white/10 p-5"><h3 className="text-xl font-black">Weekly story</h3></div><div className="space-y-3 p-4 text-sm leading-6 text-white/60"><p>@{user.username} went <b className="text-white">{report.wins}-{report.losses}</b> across {report.played.length} scored matchups and produced <b className="text-white">{report.total.toFixed(1)} total points</b>.</p><div className="grid grid-cols-2 gap-3"><Stat label="Biggest win" value={best&&best.margin>0?`+${best.margin.toFixed(1)}`:"—"} detail={best?.league.name}/><Stat label="Toughest result" value={worst?`${worst.margin.toFixed(1)}`:"—"} detail={worst?.league.name}/></div>{report.performers[0]?<div className="rounded-2xl bg-cyan-300/[0.045] p-4"><div className="text-[10px] uppercase tracking-wider text-cyan-100/45">Portfolio MVP</div><div className="mt-1 text-lg font-black">{report.performers[0].name}</div><div className="text-xs text-white/38">{report.performers[0].points.toFixed(1)} points across all rostered appearances</div></div>:null}</div></Panel><Panel className="overflow-hidden"><div className="border-b border-white/10 p-5"><h3 className="text-xl font-black">Activity and decisions</h3></div><div className="grid grid-cols-3 gap-3 p-4"><Stat label="Trades" value={trades}/><Stat label="Waivers" value={waivers}/><Stat label="Free-agent adds" value={adds}/></div><div className="px-4 pb-4 text-xs leading-5 text-white/38">Bench gap compares actual starter points with the highest-scoring players on the recorded roster; it is directional and does not reconstruct every positional eligibility constraint.</div></Panel></div><Panel className="overflow-hidden"><details open><summary className="cursor-pointer list-none p-5 text-xl font-black">League-by-league results · {report.played.length}</summary><div className="grid gap-2 border-t border-white/10 p-4 sm:grid-cols-2 xl:grid-cols-3">{report.margins.sort((a,b)=>b.margin-a.margin).map(row=><div key={row.league.league_id} className="rounded-2xl bg-white/[0.03] p-3"><div className="truncate font-semibold">{row.league.name}</div><div className="mt-2 flex justify-between text-xs"><span>{num(row.mine.points).toFixed(1)} – {num(row.opponent.points).toFixed(1)}</span><b className={row.margin>=0?"text-emerald-100":"text-rose-100"}>{row.margin>=0?"W":"L"} {Math.abs(row.margin).toFixed(1)}</b></div></div>)}</div></details></Panel></>:null}</div>;
}

function RivalryCenter({ initialLeft="", season, players }) {
  const [names,setNames]=useState([initialLeft,""]);
  const [data,setData]=useState(null);
  const [errors,setErrors]=useState(["",""]);
  const [loading,setLoading]=useState(false);
  useEffect(()=>{if(initialLeft)setNames(current=>[current[0]||initialLeft,current[1]]);},[initialLeft]);
  const build=async(event)=>{
    event.preventDefault();const clean=names.map(name=>name.trim());const nextErrors=clean.map((name,index)=>name?"":`Enter manager ${index+1}.`);if(nextErrors.some(Boolean)){setErrors(nextErrors);return;}setLoading(true);setErrors(["",""]);
    try{
      const users=await Promise.all(clean.map(async name=>{const response=await fetch(`https://api.sleeper.app/v1/user/${encodeURIComponent(name)}`,{cache:"no-store"});if(!response.ok)throw new Error(name);const user=await response.json();if(!user?.user_id)throw new Error(name);return user;}));
      const years=Array.from({length:6},(_,index)=>season-index);
      const histories=await Promise.all(users.map(user=>Promise.all(years.map(async year=>({year,leagues:await getJson(`https://api.sleeper.app/v1/user/${user.user_id}/leagues/nfl/${year}`).catch(()=>[])})))));
      const shared=years.flatMap((year,index)=>histories[0][index].leagues.filter(league=>histories[1][index].leagues.some(other=>String(other.league_id)===String(league.league_id))).map(league=>({year,league})));
      const leagueRows=await concurrentMap(shared,4,async row=>{
        const rosters=await getJson(`https://api.sleeper.app/v1/league/${row.league.league_id}/rosters`).catch(()=>[]);
        const rosterIds=users.map(user=>String(rosters.find(roster=>String(roster.owner_id)===String(user.user_id))?.roster_id||""));
        const weeks=await concurrentMap(Array.from({length:18},(_,index)=>index+1),6,async week=>{
          const [matchups,transactions]=await Promise.all([
            getJson(`https://api.sleeper.app/v1/league/${row.league.league_id}/matchups/${week}`).catch(()=>[]),
            getJson(`https://api.sleeper.app/v1/league/${row.league.league_id}/transactions/${week}`).catch(()=>[]),
          ]);
          const sides=rosterIds.map(id=>matchups.find(matchup=>String(matchup.roster_id)===id));
          const headToHead=sides[0]&&sides[1]&&String(sides[0].matchup_id)===String(sides[1].matchup_id)?{week,left:sides[0],right:sides[1]}:null;
          const trades=transactions.filter(tx=>tx.type==="trade"&&rosterIds.every(id=>(tx.roster_ids||[]).map(String).includes(id)));
          return{headToHead,trades};
        });
        return{...row,rosterIds,games:weeks.map(item=>item.headToHead).filter(Boolean),trades:weeks.flatMap(item=>item.trades)};
      });
      const games=leagueRows.flatMap(row=>row.games.map(game=>({...game,league:row.league,year:row.year})));
      const leftWins=games.filter(game=>num(game.left.points)>num(game.right.points)).length;
      const rightWins=games.filter(game=>num(game.right.points)>num(game.left.points)).length;
      const ties=games.length-leftWins-rightWins;
      const trades=leagueRows.flatMap(row=>row.trades.map(tx=>({tx,league:row.league,year:row.year})));
      setData({users,shared,leagueRows,games,leftWins,rightWins,ties,trades});
    }catch(error){const failed=clean.find(name=>name===error?.message);setErrors(failed?clean.map(name=>name===failed?`No Sleeper manager was found for “${name}”.`:""):["Rivalry history could not be loaded.","Rivalry history could not be loaded."]);}
    finally{setLoading(false);}
  };
  const closest=data?.games?.slice().sort((a,b)=>Math.abs(num(a.left.points)-num(a.right.points))-Math.abs(num(b.left.points)-num(b.right.points)))[0];
  const biggest=data?.games?.slice().sort((a,b)=>Math.abs(num(b.left.points)-num(b.right.points))-Math.abs(num(a.left.points)-num(a.right.points)))[0];
  const totals=data?data.games.reduce((sum,game)=>({left:sum.left+num(game.left.points),right:sum.right+num(game.right.points)}),{left:0,right:0}):null;
  return <div className="mt-5 space-y-4"><Panel className="overflow-hidden"><div className="border-b border-white/10 bg-[radial-gradient(circle_at_90%_0%,rgba(244,114,182,.14),transparent_40%)] p-5"><div className="text-[10px] font-semibold uppercase tracking-[.2em] text-pink-200/55">Rivalry center</div><h2 className="mt-1 text-2xl font-black">The complete history between two managers</h2><p className="mt-1 text-xs text-white/38">Scans up to six seasons of shared leagues, head-to-head matchups, and direct trades.</p></div><form onSubmit={build} className="grid gap-3 p-4 lg:grid-cols-[1fr_1fr_auto] lg:items-start">{[0,1].map(index=><label key={index} className="text-xs text-white/45">Manager {index+1}<input value={names[index]} onChange={event=>setNames(current=>current.map((name,i)=>i===index?event.target.value:name))} className="mt-1.5 w-full rounded-xl border border-white/10 bg-slate-950 px-4 py-3 text-sm text-white"/>{errors[index]?<span className="mt-1 block text-rose-200">{errors[index]}</span>:null}</label>)}<button disabled={loading} className="rounded-xl bg-pink-300/10 px-5 py-3 text-sm font-bold text-pink-100 disabled:opacity-50 lg:mt-5">{loading?"Building rivalry…":"Build rivalry"}</button></form></Panel>{data?<><section className="grid grid-cols-2 gap-3 sm:grid-cols-4 xl:grid-cols-8"><Stat label={data.users[0].display_name||data.users[0].username} value={data.leftWins}/><Stat label={data.users[1].display_name||data.users[1].username} value={data.rightWins}/><Stat label="Ties" value={data.ties}/><Stat label="Meetings" value={data.games.length}/><Stat label="Shared leagues" value={data.shared.length}/><Stat label="Shared seasons" value={new Set(data.shared.map(row=>row.year)).size}/><Stat label="Direct trades" value={data.trades.length}/><Stat label="Total points" value={`${totals.left.toFixed(0)}–${totals.right.toFixed(0)}`}/></section><div className="grid gap-4 xl:grid-cols-2"><Panel className="p-5"><h3 className="text-xl font-black">Rivalry moments</h3><div className="mt-4 grid grid-cols-2 gap-3"><Stat label="Closest meeting" value={closest?Math.abs(num(closest.left.points)-num(closest.right.points)).toFixed(1):"—"} detail={closest?`${closest.league.name} · W${closest.week}`:"No meetings"}/><Stat label="Largest margin" value={biggest?Math.abs(num(biggest.left.points)-num(biggest.right.points)).toFixed(1):"—"} detail={biggest?`${biggest.league.name} · W${biggest.week}`:"No meetings"}/></div></Panel><Panel className="overflow-hidden"><details open><summary className="cursor-pointer list-none p-5 text-xl font-black">Season timeline</summary><div className="divide-y divide-white/[0.06] border-t border-white/10">{Array.from(new Set(data.shared.map(row=>row.year))).sort((a,b)=>b-a).map(year=>{const rows=data.leagueRows.filter(row=>row.year===year);const games=rows.flatMap(row=>row.games);const left=games.filter(game=>num(game.left.points)>num(game.right.points)).length;const right=games.filter(game=>num(game.right.points)>num(game.left.points)).length;return <div key={year} className="p-4"><div className="flex justify-between"><b>{year}</b><span className="text-xs text-white/35">{left}-{right} · {rows.length} shared leagues</span></div><div className="mt-2 text-xs text-white/40">{rows.map(row=>row.league.name).join(" · ")}</div></div>;})}</div></details></Panel></div><Panel className="overflow-hidden"><details open><summary className="cursor-pointer list-none p-5 text-xl font-black">Matchup archive · {data.games.length}</summary><div className="grid gap-2 border-t border-white/10 p-4 sm:grid-cols-2 xl:grid-cols-3">{data.games.slice().sort((a,b)=>b.year-a.year||b.week-a.week).map((game,index)=>{const leftWon=num(game.left.points)>=num(game.right.points);return <div key={`${game.league.league_id}:${game.week}:${index}`} className="rounded-2xl bg-white/[0.03] p-3"><div className="truncate font-semibold">{game.league.name}</div><div className="mt-1 text-[10px] text-white/30">{game.year} · Week {game.week}</div><div className="mt-2 flex justify-between text-xs"><span>{num(game.left.points).toFixed(1)} – {num(game.right.points).toFixed(1)}</span><b className={leftWon?"text-cyan-100":"text-violet-100"}>{leftWon?data.users[0].display_name||data.users[0].username:data.users[1].display_name||data.users[1].username}</b></div></div>;})}</div></details></Panel><Panel className="overflow-hidden"><details><summary className="cursor-pointer list-none p-5 text-xl font-black">Direct trade history · {data.trades.length}</summary><div className="divide-y divide-white/[0.06] border-t border-white/10">{data.trades.length?data.trades.map(({tx,league,year},index)=><div key={`${tx.transaction_id}:${index}`} className="p-4"><div className="font-semibold">{league.name}</div><div className="mt-1 text-xs text-white/38">{year} · {Object.keys(tx.adds||{}).length} players · {(tx.draft_picks||[]).length} picks · {tx.created?new Date(num(tx.created)).toLocaleDateString():"Date unavailable"}</div></div>):<div className="p-5 text-sm text-white/38">No direct trades were found in the scanned rivalry seasons.</div>}</div></details></Panel></>:null}</div>;
}

function ManagerAnalytics({ profile, profileData, leagueData, rootUser, players }) {
  if (!profileData) return null;
  const details = profileData.details || [];
  const currentLeagues = details.length;
  const wins = details.reduce((sum,row)=>sum+num(row.mine?.settings?.wins),0);
  const losses = details.reduce((sum,row)=>sum+num(row.mine?.settings?.losses),0);
  const ties = details.reduce((sum,row)=>sum+num(row.mine?.settings?.ties),0);
  const games = wins+losses+ties;
  const points = details.reduce((sum,row)=>sum+num(row.mine?.settings?.fpts)+num(row.mine?.settings?.fpts_decimal)/100,0);
  const potential = details.reduce((sum,row)=>sum+num(row.mine?.settings?.ppts)+num(row.mine?.settings?.ppts_decimal)/100,0);
  const allRosterIds = details.flatMap(row=>row.mine?.players||[]).map(String);
  const uniquePlayers = new Set(allRosterIds).size;
  const positionCounts = {};
  const teamCounts = {};
  const ages = [];
  allRosterIds.forEach(id=>{const player=players?.[id];const pos=String(player?.position||"Other").toUpperCase();positionCounts[pos]=(positionCounts[pos]||0)+1;if(player?.team)teamCounts[player.team]=(teamCounts[player.team]||0)+1;if(num(player?.age)>0)ages.push(num(player.age));});
  const positions = Object.entries(positionCounts).map(([label,count])=>({label,count})).sort((a,b)=>b.count-a.count);
  const nflTeams = Object.entries(teamCounts).map(([label,count])=>({label,count})).sort((a,b)=>b.count-a.count);
  const drafts = details.flatMap(row=>row.draftPicks||[]);
  const draftPositions = {};
  const earlyPositions = {};
  drafts.forEach(pick=>{const pos=String(players?.[pick.player_id]?.position||"Other").toUpperCase();draftPositions[pos]=(draftPositions[pos]||0)+1;if(num(pick.round)<=3)earlyPositions[pos]=(earlyPositions[pos]||0)+1;});
  const tradeCount = details.reduce((sum,row)=>sum+(row.transactions||[]).length,0);
  const dynastyCount = details.filter(row=>num(row.league?.settings?.taxi_slots)>0 || num(row.league?.settings?.draft_rounds)<=6).length;
  const bestBallCount = details.filter(row=>num(row.league?.settings?.best_ball)===1).length;
  const playerShares = new Map();
  details.forEach(row=>(row.mine?.players||[]).forEach(id=>playerShares.set(String(id),num(playerShares.get(String(id)))+1)));
  const concentrated = [...playerShares.entries()].filter(([,count])=>count>=Math.max(2,Math.ceil(currentLeagues*.4))).sort((a,b)=>b[1]-a[1]);
  const yearCounts = profileData.yearLists.map(row=>row.leagues.length);
  const activeYears = yearCounts.filter(Boolean).length;
  const leagueNames = profileData.yearLists.flatMap(row=>row.leagues.map(league=>String(league.name||"").toLowerCase().trim())).filter(Boolean);
  const recurringNames = new Set(leagueNames.filter((name,index)=>leagueNames.indexOf(name)!==index)).size;
  const selectedRootRoster = leagueData?.rosters?.find(roster=>String(roster.owner_id)===String(rootUser?.user_id));
  const selectedProfileRoster = leagueData?.rosters?.find(roster=>String(roster.owner_id)===String(profile.user?.user_id));
  const selectedOverlap = (selectedProfileRoster?.players||[]).filter(id=>(selectedRootRoster?.players||[]).map(String).includes(String(id)));
  const maxCount = Math.max(1,...positions.map(row=>row.count));
  return <section className="mt-5 space-y-5"><Panel className="overflow-hidden"><div className="border-b border-white/10 bg-[radial-gradient(circle_at_90%_0%,rgba(34,211,238,.13),transparent_40%)] p-5"><div className="text-[10px] font-semibold uppercase tracking-[.22em] text-cyan-200/55">Deep manager analytics</div><h2 className="mt-1 text-2xl font-black">Portfolio and decision profile</h2><p className="mt-1 text-xs leading-5 text-white/38">Descriptive tendencies from public Sleeper records—not grades of skill, character, or intent.</p></div><div className="grid grid-cols-2 gap-3 p-5 sm:grid-cols-4 xl:grid-cols-8"><Stat label="Combined record" value={`${wins}-${losses}`} detail={ties?`${ties} ties`:games?`${Math.round(wins/games*100)}% win rate`:"No games"}/><Stat label="Fantasy points" value={Math.round(points).toLocaleString()} detail="Across current leagues"/><Stat label="Lineup capture" value={potential?`${Math.round(points/potential*100)}%`:"—"} detail="Points vs potential points"/><Stat label="Avg. player age" value={ages.length?(ages.reduce((a,b)=>a+b,0)/ages.length).toFixed(1):"—"}/><Stat label="Unique players" value={uniquePlayers}/><Stat label="Trade events" value={tradeCount} detail="Scanned transaction window"/><Stat label="Active seasons" value={activeYears} detail="Of six seasons scanned"/><Stat label="Recurring leagues" value={recurringNames} detail="Name-level continuity signal"/></div></Panel>
  <div className="grid gap-5 xl:grid-cols-3"><Panel className="p-5"><h3 className="text-xl font-black">Portfolio identity</h3><div className="mt-4 grid grid-cols-2 gap-3"><Stat label="Dynasty profile" value={dynastyCount}/><Stat label="Best ball" value={bestBallCount}/><Stat label="Other formats" value={Math.max(0,currentLeagues-dynastyCount)}/><Stat label="Roster spots" value={allRosterIds.length}/></div><div className="mt-4 text-xs leading-5 text-white/40">{dynastyCount>currentLeagues*.65?"Portfolio leans heavily toward dynasty roster construction.":bestBallCount>currentLeagues*.4?"Best-ball formats are a meaningful part of this portfolio.":"Portfolio format mix is relatively broad or primarily seasonal."}</div></Panel>
  <Panel className="p-5"><h3 className="text-xl font-black">Position allocation</h3><div className="mt-4 space-y-3">{positions.slice(0,8).map(row=><div key={row.label}><div className="flex justify-between text-xs"><b>{row.label}</b><span className="text-white/35">{row.count} shares</span></div><div className="mt-1.5 h-1.5 rounded bg-white/[0.05]"><div className="h-full rounded bg-cyan-300" style={{width:`${row.count/maxCount*100}%`}}/></div></div>)}</div></Panel>
  <Panel className="p-5"><h3 className="text-xl font-black">NFL team exposure</h3><p className="mt-1 text-xs text-white/35">Concentration can reflect stacks, preferences, or coincidence.</p><div className="mt-4 grid grid-cols-3 gap-2">{nflTeams.slice(0,9).map(row=><div key={row.label} className="rounded-xl bg-white/[0.03] p-2 text-center"><b>{row.label}</b><small className="block text-[9px] text-white/30">{row.count} shares</small></div>)}</div></Panel></div>
  <div className="grid gap-5 xl:grid-cols-2"><Panel className="p-5"><h3 className="text-xl font-black">Draft tendencies</h3><div className="mt-4 grid gap-3 sm:grid-cols-2"><div className="rounded-2xl bg-white/[0.025] p-4"><div className="text-[10px] font-semibold uppercase text-white/30">All recorded picks</div><div className="mt-3 flex flex-wrap gap-2">{Object.entries(draftPositions).sort((a,b)=>b[1]-a[1]).map(([pos,count])=><span key={pos} className="rounded-lg bg-violet-300/[0.07] px-2.5 py-1.5 text-xs"><b>{pos}</b> {count}</span>)}</div></div><div className="rounded-2xl bg-white/[0.025] p-4"><div className="text-[10px] font-semibold uppercase text-white/30">Rounds 1–3</div><div className="mt-3 flex flex-wrap gap-2">{Object.entries(earlyPositions).sort((a,b)=>b[1]-a[1]).map(([pos,count])=><span key={pos} className="rounded-lg bg-amber-300/[0.07] px-2.5 py-1.5 text-xs"><b>{pos}</b> {count}</span>)}</div></div></div></Panel>
  <Panel className="p-5"><h3 className="text-xl font-black">Conviction and comparison</h3><div className="mt-4 space-y-3"><div className="rounded-2xl bg-white/[0.025] p-4"><div className="text-[10px] font-semibold uppercase text-white/30">Repeated player exposure</div><div className="mt-2 text-sm text-white/55">{concentrated.length?`${concentrated.length} players appear on at least 40% of this manager's current teams.`:"No player reaches the 40% portfolio-concentration threshold."}</div></div><div className="rounded-2xl bg-white/[0.025] p-4"><div className="text-[10px] font-semibold uppercase text-white/30">Roster overlap with searched manager</div><div className="mt-2 text-sm text-white/55">{selectedOverlap.length?`${selectedOverlap.length} shared players in the selected league's two rosters.`:"No same-player overlap in the selected league rosters."}</div>{selectedOverlap.length?<div className="mt-2 text-xs text-white/35">{selectedOverlap.slice(0,10).map(id=>players?.[id]?.full_name||id).join(" · ")}</div>:null}</div></div></Panel></div></section>;
}

export default function ManagerIntelligenceClient(){
  const {username:loggedIn,players}=useSleeper();
  const [query,setQuery]=useState(""); const [searched,setSearched]=useState(""); const [rootUser,setRootUser]=useState(null); const [season,setSeason]=useState(seasonNow); const [leagues,setLeagues]=useState([]); const [leagueId,setLeagueId]=useState(""); const [leagueData,setLeagueData]=useState(null); const [profile,setProfile]=useState(null); const [profileData,setProfileData]=useState(null); const [viewTab,setViewTab]=useState("profile"); const [loading,setLoading]=useState(false); const [profileLoading,setProfileLoading]=useState(false); const [error,setError]=useState("");
  useEffect(()=>{if(loggedIn&&!query)setQuery(loggedIn);},[loggedIn,query]);
  const search=async(event)=>{event?.preventDefault();if(!query.trim())return;setLoading(true);setError("");setLeagueData(null);setProfile(null);try{const user=await getJson(`https://api.sleeper.app/v1/user/${encodeURIComponent(query.trim())}`);const rows=await getJson(`https://api.sleeper.app/v1/user/${user.user_id}/leagues/nfl/${season}`);setRootUser(user);setSearched(user.username||query.trim());setLeagues(rows||[]);setLeagueId(String(rows?.[0]?.league_id||""));setViewTab("profile");await openProfile(user,null);}catch{setError("That Sleeper user or season could not be loaded.");setLeagues([]);}finally{setLoading(false);}};
  useEffect(()=>{if(!rootUser)return;search();/* eslint-disable-next-line react-hooks/exhaustive-deps */},[season]);
  useEffect(()=>{let active=true;if(!leagueId){setLeagueData(null);return;}setLoading(true);Promise.all([getJson(`https://api.sleeper.app/v1/league/${leagueId}`),getJson(`https://api.sleeper.app/v1/league/${leagueId}/rosters`),getJson(`https://api.sleeper.app/v1/league/${leagueId}/users`),Promise.all(Array.from({length:19},(_,week)=>getJson(`https://api.sleeper.app/v1/league/${leagueId}/transactions/${week}`).catch(()=>[]))).then(rows=>rows.flat())]).then(([league,rosters,users,transactions])=>active&&setLeagueData({league,rosters,users,transactions})).catch(()=>active&&setError("League members and activity could not be loaded.")).finally(()=>active&&setLoading(false));return()=>{active=false;};},[leagueId]);
  const openProfile=async(user,roster)=>{
    if(!user?.user_id)return;
    setProfile({user,roster});setViewTab("profile");setProfileLoading(true);setProfileData(null);
    try{
      const years=Array.from({length:6},(_,index)=>season-index);
      const yearLists=await Promise.all(years.map(async(year)=>({year,leagues:await getJson(`https://api.sleeper.app/v1/user/${user.user_id}/leagues/nfl/${year}`).catch(()=>[])})));
      const current=yearLists[0]?.leagues||[];
      setRootUser(user);setSearched(user.username||user.display_name||"");setQuery(user.username||user.display_name||"");setLeagues(current);
      const details=await concurrentMap(current,10,async(league,index)=>{
        const rosters=await getJson(`https://api.sleeper.app/v1/league/${league.league_id}/rosters`).catch(()=>[]);
        const mine=rosters.find(row=>String(row.owner_id)===String(user.user_id));
        if(index>=30)return{league,mine,transactions:[],draftPicks:[]};
        const [drafts,transactions]=await Promise.all([
          getJson(`https://api.sleeper.app/v1/league/${league.league_id}/drafts`).catch(()=>[]),
          getJson(`https://api.sleeper.app/v1/league/${league.league_id}/transactions/1`).catch(()=>[]),
        ]);
        const draftPicks=(await Promise.all(drafts.slice(0,2).map(draft=>getJson(`https://api.sleeper.app/v1/draft/${draft.draft_id}/picks`).catch(()=>[])))).flat().filter(pick=>String(pick.picked_by)===String(user.user_id));
        return{league,mine,transactions:transactions.filter(tx=>tx.type==="trade"&&(tx.roster_ids||[]).map(String).includes(String(mine?.roster_id))),draftPicks};
      });
      setProfileData({yearLists,details});
    }finally{setProfileLoading(false);}
  };
  const currentOwners=useMemo(()=>{if(!leagueData)return[];const users=new Map(leagueData.users.map(user=>[String(user.user_id),user]));return leagueData.rosters.map(roster=>({roster,user:users.get(String(roster.owner_id))})).sort((a,b)=>{const aRoot=String(a.user?.user_id)===String(rootUser?.user_id);const bRoot=String(b.user?.user_id)===String(rootUser?.user_id);if(aRoot!==bRoot)return aRoot?-1:1;return nameFor(a.user,a.roster).localeCompare(nameFor(b.user,b.roster));});},[leagueData,rootUser?.user_id]);
  const activityByRoster=useMemo(()=>{const summary={};(leagueData?.rosters||[]).forEach(roster=>{summary[String(roster.roster_id)]={total:0,trades:0,waivers:0,freeAgents:0};});(leagueData?.transactions||[]).forEach(tx=>{const rosterIds=new Set([...(tx.roster_ids||[]),...Object.values(tx.adds||{}),...Object.values(tx.drops||{})].map(String));rosterIds.forEach(id=>{if(!summary[id])return;summary[id].total+=1;if(tx.type==="trade")summary[id].trades+=1;else if(tx.type==="waiver")summary[id].waivers+=1;else if(tx.type==="free_agent")summary[id].freeAgents+=1;});});return summary;},[leagueData]);
  const exposure=useMemo(()=>{const map=new Map();(profileData?.details||[]).forEach(row=>(row.mine?.players||[]).forEach(id=>{const current=map.get(id)||{id,count:0,leagues:[]};current.count+=1;current.leagues.push(row.league.name);map.set(id,current);}));return[...map.values()].sort((a,b)=>b.count-a.count).slice(0,40);},[profileData]);
  const allTrades=useMemo(()=>(profileData?.details||[]).flatMap(row=>row.transactions.map(transaction=>({transaction,league:row.league,mine:row.mine}))).sort((a,b)=>num(b.transaction.created)-num(a.transaction.created)).slice(0,30),[profileData]);
  const allDrafts=useMemo(()=>(profileData?.details||[]).flatMap(row=>row.draftPicks.map(pick=>({...pick,leagueName:row.league.name}))).sort((a,b)=>num(b.pick_no)-num(a.pick_no)).slice(0,50),[profileData]);
  const sharedLeagueCount=(profileData?.yearLists||[]).reduce((sum,row)=>sum+row.leagues.filter(league=>(leagues||[]).some(root=>String(root.league_id)===String(league.league_id))).length,0);
  return <main className="min-h-screen text-white"><BackgroundParticles/><Navbar pageTitle="Manager Intelligence"/><div className="mx-auto max-w-7xl px-4 pb-20 pt-20"><header className="rounded-[34px] border border-violet-300/15 bg-[radial-gradient(circle_at_88%_0%,rgba(139,92,246,.22),transparent_36%),radial-gradient(circle_at_8%_100%,rgba(34,211,238,.14),transparent_34%),linear-gradient(145deg,rgba(15,23,42,.98),rgba(2,6,23,.96))] p-5 sm:p-7"><div className="text-[11px] font-semibold uppercase tracking-[.28em] text-violet-200/60">Public Sleeper manager research</div><h1 className="mt-2 text-3xl font-black sm:text-5xl">Search a manager. See the whole portfolio.</h1><p className="mt-3 max-w-3xl text-sm leading-6 text-white/52">Enter one Sleeper username to open their complete manager profile, then move through their leagues, league-mates, player stock, trades, records, and draft history.</p><form onSubmit={search} className="mt-6 grid gap-3 sm:grid-cols-[1fr_120px_auto]"><input value={query} onChange={event=>setQuery(event.target.value)} placeholder="Sleeper username" className="rounded-2xl border border-white/10 bg-slate-950 px-4 py-3"/><select value={season} onChange={event=>setSeason(num(event.target.value))} className="rounded-2xl border border-white/10 bg-slate-950 px-3">{Array.from({length:7},(_,index)=>seasonNow-index).map(year=><option key={year}>{year}</option>)}</select><button className="rounded-2xl bg-violet-300/10 px-5 py-3 font-bold text-violet-100">{loading||profileLoading?"Building profile…":"Search manager"}</button></form></header>{error?<div className="mt-5 rounded-2xl border border-rose-300/15 bg-rose-300/[0.07] p-4 text-sm text-rose-100">{error}</div>:null}{rootUser?<section className="mt-5 grid grid-cols-2 gap-3 sm:grid-cols-4"><Stat label="Manager" value={rootUser.display_name||searched}/><Stat label="Season" value={season}/><Stat label="Leagues" value={leagues.length}/><Stat label="Selected league" value={leagueData?.league?.name||"—"}/></section>:null}
  {rootUser?<nav className="mt-5 overflow-x-auto rounded-2xl border border-white/10 bg-slate-950/80 p-2"><div className="flex w-max gap-1">{[["profile","Manager Profile"],["network","Leagues"],["compare","Compare Owners"],["weekly","Weekly Report"],["rivalry","Rivalry Center"]].map(([key,label])=><button key={key} onClick={()=>setViewTab(key)} className={`rounded-xl px-4 py-2.5 text-sm font-semibold transition ${viewTab===key?"bg-violet-300/12 text-violet-100":"text-white/45 hover:bg-white/5 hover:text-white"}`}>{label}</button>)}</div></nav>:null}
  {viewTab==="network"&&leagues.length?<Panel className="mt-5 overflow-hidden"><div className="border-b border-white/10 p-5"><h2 className="text-2xl font-black">{profile?.user?.display_name||rootUser?.display_name||searched}’s leagues</h2><p className="mt-1 text-xs text-white/38">Choose a league to load its complete transaction activity and every current owner.</p></div><div className="grid gap-3 p-4 md:grid-cols-2 xl:grid-cols-3">{leagues.map(league=>{const detail=(profileData?.details||[]).find(row=>String(row.league.league_id)===String(league.league_id));const selected=String(leagueId)===String(league.league_id);const mine=detail?.mine;const activity=selected?activityByRoster[String(mine?.roster_id)]?.total:null;return <button type="button" key={league.league_id} onClick={()=>setLeagueId(String(league.league_id))} className={`rounded-2xl border p-4 text-left transition hover:-translate-y-0.5 ${selected?"border-cyan-300/25 bg-cyan-300/[0.07]":"border-white/10 bg-white/[0.025] hover:bg-white/[0.05]"}`}><div className="flex items-start justify-between gap-3"><div className="min-w-0"><div className="truncate font-black">{league.name}</div><div className="mt-1 text-xs text-white/35">{league.total_rosters||"—"} teams · {league.settings?.type===2?"Dynasty":"Seasonal"}</div></div>{selected?<span className="rounded-full bg-cyan-300/10 px-2 py-1 text-[9px] font-bold uppercase text-cyan-100">Open</span>:null}</div><div className="mt-3 grid grid-cols-3 gap-2 text-center text-xs"><div><b>{num(mine?.settings?.wins)}-{num(mine?.settings?.losses)}</b><small className="block text-[9px] text-white/28">Record</small></div><div><b>{num(mine?.settings?.fpts).toLocaleString()}</b><small className="block text-[9px] text-white/28">Points</small></div><div><b>{activity==null?"Open":activity}</b><small className="block text-[9px] text-white/28">Activities</small></div></div></button>;})}</div></Panel>:null}
  {viewTab==="network"&&leagueData?<Panel className="mt-5 overflow-hidden"><div className="border-b border-white/10 p-5"><h2 className="text-2xl font-black">{leagueData.league?.name} activity</h2><p className="mt-1 text-xs text-white/38">Accepted trades, waivers, and free-agent moves across transaction periods 0–18. Select an owner to open their complete portfolio.</p></div><div className="grid gap-3 p-4 md:grid-cols-2 xl:grid-cols-3">{currentOwners.map(({roster,user})=>{const activity=activityByRoster[String(roster.roster_id)]||{};return <button key={roster.roster_id} onClick={()=>openProfile(user,roster)} className="rounded-2xl border border-white/10 bg-white/[0.025] p-4 text-left transition hover:-translate-y-0.5 hover:bg-white/[0.05]"><div className="flex items-center gap-3">{user?.avatar?<img src={`https://sleepercdn.com/avatars/thumbs/${user.avatar}`} alt="" className="h-11 w-11 rounded-2xl"/>:<div className="grid h-11 w-11 place-items-center rounded-2xl bg-white/[0.05]">R{roster.roster_id}</div>}<div className="min-w-0 flex-1"><div className="truncate font-black">{nameFor(user,roster)}</div><div className="truncate text-xs text-white/35">@{user?.username||"open roster"} · {num(roster.settings?.wins)}-{num(roster.settings?.losses)}</div></div><span className="text-cyan-100/45">→</span></div><div className="mt-3 grid grid-cols-4 gap-2 text-center text-xs"><div><b>{activity.total||0}</b><small className="block text-[9px] text-white/28">Total</small></div><div><b>{activity.trades||0}</b><small className="block text-[9px] text-white/28">Trades</small></div><div><b>{activity.waivers||0}</b><small className="block text-[9px] text-white/28">Waivers</small></div><div><b>{activity.freeAgents||0}</b><small className="block text-[9px] text-white/28">Adds</small></div></div></button>;})}</div></Panel>:null}
  {viewTab==="compare"?<OpenManagerCompare season={season} players={players} initialLeft={profile?.user?.username||searched}/>:null}
  {viewTab==="weekly"?<WeeklyPortfolioReport user={profile?.user||rootUser} leagues={leagues} season={season} players={players}/>:null}
  {viewTab==="rivalry"?<RivalryCenter initialLeft={profile?.user?.username||searched} season={season} players={players}/>:null}
  {viewTab==="profile"&&profile?<div className="mt-5 space-y-5"><Panel className="p-5"><div className="flex items-center gap-4">{profile.user.avatar?<img src={`https://sleepercdn.com/avatars/thumbs/${profile.user.avatar}`} alt="" className="h-16 w-16 rounded-3xl"/>:null}<div><div className="text-2xl font-black">{profile.user.display_name||profile.user.username}</div><div className="text-sm text-white/38">@{profile.user.username}</div></div></div>{profileLoading?<div className="mt-5 text-sm text-cyan-100">Building multi-league profile…</div>:profileData?<div className="mt-5 grid grid-cols-2 gap-3 sm:grid-cols-4"><Stat label="Current leagues" value={profileData.details.length}/><Stat label="Six-year leagues" value={profileData.yearLists.reduce((sum,row)=>sum+row.leagues.length,0)}/><Stat label="Shared with search" value={sharedLeagueCount}/><Stat label="Unique rostered" value={new Set(profileData.details.flatMap(row=>row.mine?.players||[])).size}/></div>:null}</Panel>{profileData?<><ManagerAnalytics profile={profile} profileData={profileData} leagueData={leagueData} rootUser={rootUser} players={players}/><div className="grid gap-5 xl:grid-cols-2"><Panel className="overflow-hidden"><div className="border-b border-white/10 p-5"><h3 className="text-xl font-black">Player stock</h3><p className="mt-1 text-xs text-white/35">Most frequently rostered across current-season leagues.</p></div><div className="divide-y divide-white/[0.06]">{exposure.slice(0,15).map(row=><details key={row.id} className="p-3"><summary className="flex cursor-pointer list-none items-center gap-3"><AvatarImage name={players?.[row.id]?.full_name} playerId={row.id} size={36} className="rounded-xl" alt=""/><div className="min-w-0 flex-1"><div className="truncate font-semibold">{players?.[row.id]?.full_name||row.id}</div><div className="text-xs text-white/32">{players?.[row.id]?.position||"—"}</div></div><b className="text-cyan-100">{row.count} shares</b></summary><div className="mt-2 pl-12 text-xs leading-5 text-white/38">{row.leagues.join(" · ")}</div></details>)}</div></Panel><Panel className="overflow-hidden"><div className="border-b border-white/10 p-5"><h3 className="text-xl font-black">League history by year</h3><p className="mt-1 text-xs text-white/35">Open a league to browse its managers.</p></div><div className="divide-y divide-white/[0.06]">{profileData.yearLists.map(row=><details key={row.year} className="p-4"><summary className="flex cursor-pointer list-none justify-between font-semibold"><span>{row.year}</span><span className="text-white/35">{row.leagues.length} leagues</span></summary><div className="mt-3 grid gap-2">{row.leagues.map(league=><button type="button" key={league.league_id} onClick={()=>{setLeagueId(String(league.league_id));setViewTab("network");}} className="flex items-center justify-between rounded-xl bg-white/[0.025] px-3 py-2.5 text-left text-xs text-white/55 transition hover:bg-white/[0.06] hover:text-white"><span className="truncate">{league.name} · {league.total_rosters} teams</span><span className="ml-3 text-cyan-100/45">View members →</span></button>)}</div></details>)}</div></Panel></div><div className="grid gap-5 xl:grid-cols-2"><Panel className="overflow-hidden"><div className="border-b border-white/10 p-5"><h3 className="text-xl font-black">Recent public trades</h3></div><div className="divide-y divide-white/[0.06]">{allTrades.length?allTrades.map(({transaction,league})=><div key={transaction.transaction_id} className="p-4"><div className="font-semibold">{league.name}</div><div className="mt-1 text-xs text-white/38">{Object.keys(transaction.adds||{}).length} players moved · {(transaction.draft_picks||[]).length} picks · {transaction.created?new Date(num(transaction.created)).toLocaleDateString():"Date unavailable"}</div></div>):<div className="p-6 text-sm text-white/35">No trades found in the scanned transaction window.</div>}</div></Panel><Panel className="overflow-hidden"><div className="border-b border-white/10 p-5"><h3 className="text-xl font-black">Draft history</h3></div><div className="divide-y divide-white/[0.06]">{allDrafts.length?allDrafts.map((pick,index)=><div key={`${pick.draft_id}:${pick.pick_no}:${index}`} className="flex items-center gap-3 p-3"><b className="text-xs text-violet-100">{pick.round}.{String(pick.draft_slot).padStart(2,"0")}</b><AvatarImage name={players?.[pick.player_id]?.full_name} playerId={pick.player_id} size={34} className="rounded-xl" alt=""/><div className="min-w-0"><div className="truncate text-sm font-semibold">{players?.[pick.player_id]?.full_name||pick.player_id}</div><div className="truncate text-[10px] text-white/30">{pick.leagueName}</div></div></div>):<div className="p-6 text-sm text-white/35">No draft selections found.</div>}</div></Panel></div></>:null}</div>:null}
  <Panel className="mt-5 p-4 text-[10px] leading-5 text-white/30">All information shown is returned by Sleeper's public, read-only API. Shared leagues, trade frequency, and roster preferences are context—not proof of coordination, reliability, or misconduct.</Panel></div></main>;
}
